parameters.jsCode:
const cfg = $node['Configuración1'].json;

const parseSnapshot = (value) => {
  try {
    if (!value) return {};
    if (typeof value === 'string') return JSON.parse(value);
    if (typeof value === 'object') return value;
    return {};
  } catch (e) {
    return {};
  }
};

const safeNodeItems = (nodeName) => {
  try {
    return $(nodeName).all().map((i) => i.json);
  } catch (e) {
    return [];
  }
};

const flattenItems = (arr) => {
  const out = [];
  for (const it of arr) {
    if (Array.isArray(it)) out.push(...it);
    else if (it && typeof it === 'object') out.push(it);
  }
  return out;
};

const isCard = (x) =>
  x &&
  typeof x === 'object' &&
  typeof x.id === 'string' &&
  x.id.length === 24 &&
  Object.prototype.hasOwnProperty.call(x, 'dueComplete');

const isCommit = (x) =>
  x &&
  typeof x === 'object' &&
  typeof x.sha === 'string' &&
  x.commit &&
  typeof x.commit === 'object';

let cards = flattenItems(safeNodeItems('Trello Cards Delta1')).filter(isCard);
let backCommits = flattenItems(safeNodeItems('GitHub Back Main1')).filter(isCommit);
let frontCommits = flattenItems(safeNodeItems('GitHub Front Main1')).filter(isCommit);

const pgRows = flattenItems(safeNodeItems('PG Estado Conocido1'));
let prevSnapshot = parseSnapshot(pgRows[pgRows.length - 1]?.snapshot || pgRows[0]?.snapshot);

if (!cards.length || !backCommits.length || !frontCommits.length || !Object.keys(prevSnapshot).length) {
  const mergedRaw = $input.all().map((i) => i.json);
  const mergedFlat = flattenItems(mergedRaw);

  const fbCards = [];
  const fbBack = [];
  const fbFront = [];
  let fbSnapshot = {};

  for (const it of mergedFlat) {
    if (it?.snapshot && !Object.keys(fbSnapshot).length) {
      fbSnapshot = parseSnapshot(it.snapshot);
      continue;
    }

    if (isCard(it)) {
      fbCards.push(it);
      continue;
    }

    if (isCommit(it)) {
      const url = String(it.url || it.html_url || '');
      if (url.includes(cfg.GITHUB_REPO_BACKEND)) fbBack.push(it);
      else if (url.includes(cfg.GITHUB_REPO_FRONTEND)) fbFront.push(it);
    }
  }

  if (!cards.length) cards = fbCards;
  if (!backCommits.length) backCommits = fbBack;
  if (!frontCommits.length) frontCommits = fbFront;
  if (!Object.keys(prevSnapshot).length) prevSnapshot = fbSnapshot;
}

const prev = {
  main_commit_back_sha: prevSnapshot.main_commit_back_sha || null,
  main_commit_front_sha: prevSnapshot.main_commit_front_sha || null,
  card_states: prevSnapshot.card_states || {},
  notified_event_ids: Array.isArray(prevSnapshot.notified_event_ids) ? prevSnapshot.notified_event_ids : [],
};

const previousIds = new Set(prev.notified_event_ids);
const events = [];
const seenEventIds = new Set();
const newCardStates = {};
const commitKeyword = /(feat|fix|hotfix|release|breaking|security|perf|refactor)/i;
const throttleWindow = 200;

const makeEventId = (parts) => parts.filter(Boolean).join('|');

const addEvent = (evt) => {
  const eventId = evt.event_id || makeEventId([
    evt.tipo,
    evt.detalle?.card_id,
    evt.detalle?.sha,
    (evt.detalle?.pdfs || []).map((p) => p.name).join(','),
    evt.detalle?.url,
  ]);

  if (!eventId || seenEventIds.has(eventId) || previousIds.has(eventId)) return;
  seenEventIds.add(eventId);
  evt.event_id = eventId;
  events.push(evt);
};

const getCommitSubject = (commit) =>
  String(commit?.commit?.message || '').split('\n')[0].trim();

const isMergeCommit = (subject) => {
  const normalized = subject.toLowerCase();
  return normalized.startsWith('merge ') || normalized.includes('merge pull request');
};

const isRelevantCommit = (commit) => {
  const subject = getCommitSubject(commit);
  if (!subject) return false;
  if (commitKeyword.test(subject)) return true;
  return !isMergeCommit(subject);
};

for (const c of cards) {
  const attCount = (c.attachments || []).length;
  const pdfAtts = (c.attachments || []).filter((a) =>
    (a.mimeType || '').includes('pdf') || (a.name || '').toLowerCase().endsWith('.pdf'),
  );

  newCardStates[c.id] = {
    dueComplete: !!c.dueComplete,
    attCount,
    pdfCount: pdfAtts.length,
  };

  const prevCard = prev.card_states[c.id];
  if (!prevCard) continue;

  if (!prevCard.dueComplete && c.dueComplete) {
    addEvent({
      event_id: makeEventId(['tarea_completada', c.id, 'done']),
      source: 'trello',
      severidad: 'media',
      occurred_at: c.dateLastActivity || c.due || null,
      tipo: 'tarea_completada',
      emoji: 'OK',
      titulo: 'Tarea completada',
      descripcion: 'La tarjeta "' + c.name + '" fue marcada como completada.',
      detalle: {
        card_id: c.id,
        card_name: c.name,
        due: c.due,
        list_id: c.idList,
        date_last_activity: c.dateLastActivity,
      },
    });
  }

  if ((prevCard.pdfCount || 0) < pdfAtts.length) {
    const newPdfs = pdfAtts.slice(-(pdfAtts.length - (prevCard.pdfCount || 0)));
    addEvent({
      event_id: makeEventId(['entregable_subido', c.id, newPdfs.map((p) => p.name).join('|')]),
      source: 'trello',
      severidad: 'alta',
      occurred_at: c.dateLastActivity || c.due || null,
      tipo: 'entregable_subido',
      emoji: 'PDF',
      titulo: 'Nuevo entregable PDF',
      descripcion: 'Se subio un PDF a "' + c.name + '": ' + newPdfs.map((p) => p.name).join(', '),
      detalle: {
        card_id: c.id,
        card_name: c.name,
        pdfs: newPdfs.map((p) => ({ name: p.name, url: p.url })),
        list_id: c.idList,
        date_last_activity: c.dateLastActivity,
      },
    });
  }
}

const latestBack = backCommits[0];
if (
  latestBack &&
  latestBack.sha !== prev.main_commit_back_sha &&
  prev.main_commit_back_sha &&
  isRelevantCommit(latestBack)
) {
  const subject = getCommitSubject(latestBack);
  addEvent({
    event_id: makeEventId(['commit_main_backend', latestBack.sha]),
    source: 'github',
    severidad: commitKeyword.test(subject) ? 'alta' : 'media',
    occurred_at: latestBack.commit?.author?.date || null,
    tipo: 'commit_main_backend',
    emoji: 'GH',
    titulo: 'Commit a main (backend)',
    descripcion: (latestBack.commit?.author?.name || '?') + ': ' + subject,
    detalle: {
      repo: 'backend',
      sha: latestBack.sha,
      url: latestBack.html_url,
      autor: latestBack.commit?.author?.name,
      mensaje: latestBack.commit?.message,
    },
  });
}

const latestFront = frontCommits[0];
if (
  latestFront &&
  latestFront.sha !== prev.main_commit_front_sha &&
  prev.main_commit_front_sha &&
  isRelevantCommit(latestFront)
) {
  const subject = getCommitSubject(latestFront);
  addEvent({
    event_id: makeEventId(['commit_main_frontend', latestFront.sha]),
    source: 'github',
    severidad: commitKeyword.test(subject) ? 'alta' : 'media',
    occurred_at: latestFront.commit?.author?.date || null,
    tipo: 'commit_main_frontend',
    emoji: 'GH',
    titulo: 'Commit a main (frontend)',
    descripcion: (latestFront.commit?.author?.name || '?') + ': ' + subject,
    detalle: {
      repo: 'frontend',
      sha: latestFront.sha,
      url: latestFront.html_url,
      autor: latestFront.commit?.author?.name,
      mensaje: latestFront.commit?.message,
    },
  });
}

const notified = [...events.map((e) => e.event_id), ...prev.notified_event_ids].filter(Boolean).slice(0, throttleWindow);
const newSnapshot = {
  main_commit_back_sha: latestBack?.sha || prev.main_commit_back_sha,
  main_commit_front_sha: latestFront?.sha || prev.main_commit_front_sha,
  card_states: newCardStates,
  notified_event_ids: notified,
  last_run_at: new Date().toISOString(),
};

return [{
  json: {
    events,
    event_count: events.length,
    new_snapshot: newSnapshot,
    new_snapshot_json: JSON.stringify(newSnapshot),
  },
}];

