const ev = $node['Preparar Prompt Evento1'].json;
const gem = $json;
const analysis = gem?.text || gem?.output || gem?.response || gem?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '';

let extra = '';
if (ev.detalle?.url) extra = '\n' + ev.detalle.url;
if (ev.detalle?.pdfs?.length) extra = '\n' + ev.detalle.pdfs.map((p) => p.name + ': ' + p.url).join('\n');

const metaBits = [];
if (ev.severidad) metaBits.push('Severidad: ' + ev.severidad);
if (ev.source) metaBits.push('Fuente: ' + ev.source);
if (ev.occurred_at) metaBits.push('Fecha: ' + ev.occurred_at);
const metaLine = metaBits.length ? '\n' + metaBits.join(' | ') : '';
const fallback = 'Impacto: revisar evento.\nProxima accion: validar seguimiento con el owner.\nOwner sugerido: PM | Deadline sugerido: hoy.\nRiesgo: medio - falta analisis automatico.';
const content = ('**' + (ev.emoji || 'PM') + ' ' + ev.titulo + '**\n' + ev.descripcion + extra + metaLine + '\n\n' + (analysis || fallback)).slice(0, 1900);

const detalle = {
  ...(ev.detalle || {}),
  event_id: ev.event_id || null,
  source: ev.source || null,
  severidad: ev.severidad || null,
  occurred_at: ev.occurred_at || null,
};

return [{ json: {
  ...ev,
  analysis,
  content,
  outbox_target: 'discord',
  outbox_action: 'notify',
  outbox_payload: { content },
  outbox_idempotency_key: ev.event_id || null,
  detalle_json: JSON.stringify(detalle),
}}];

